  number: string;         // formatted with leading zeros, e.g. "#001", "#042", "#100"
  name: string;           // colloquial name (e.g. "Alabau Ito")
  slug: string;           // URL-safe slug, e.g. "contemplator-001" — used to link to the site
  phrase: string;         // poetic phrase in English
  image: string;          // Cloudinary URL
  object: ObjectOfContemplation;
  state: MentalState;
  environment: Environment;
