/** Helper: get a Contemplator by its id (1..100) */
export function getContemplator(id: number): Contemplator | undefined {
  return CONTEMPLATORS.find((c) => c.id === id);
}

/** Helper: get a Contemplator by its slug (e.g. "contemplator-001") */
export function getContemplatorBySlug(slug: string): Contemplator | undefined {
  return CONTEMPLATORS.find((c) => c.slug === slug);
}
